def {{nama_fungsi}}(value, *functions):
    """Pipe value through a series of functions. Left to right.
    pipe(data, f1, f2, f3) = f3(f2(f1(data)))
    """
    result = value
    for fn in functions:
        result = fn(result)
    return result


def {{nama_fungsi_thread}}(value, *operations):
    """Thread-first macro style. Each operation is (func, *args).
    thread_first(data, (f1, arg1), (f2, arg2)) = f2(f1(data, arg1), arg2)
    """
    result = value
    for op in operations:
        if callable(op):
            result = op(result)
        elif isinstance(op, (list, tuple)):
            fn = op[0]
            args = op[1:]
            result = fn(result, *args)
        else:
            raise TypeError('Expected callable or (func, *args) tuple, got %s' % type(op))
    return result


def P(val):
    """Shorthand alias for pipe. Usage: P(data) | f1 | f2."""
    class PipeProxy:
        def __init__(self, value):
            self._value = value
        def __or__(self, func):
            return PipeProxy(func(self._value))
        def __repr__(self):
            return repr(self._value)
        def result(self):
            return self._value
    return PipeProxy(val)

def {{nama_fungsi}}(*functions):
    """Compose functions right-to-left.
    compose(f, g, h)(x) = f(g(h(x)))
    """
    def composed(value):
        result = value
        for fn in reversed(functions):
            result = fn(result)
        return result
    if functions:
        functools.update_wrapper(composed, functions[0])
    return composed


def {{nama_fungsi_pipe}}(*functions):
    """Compose functions left-to-right (pipe style).
    compose_left(f, g, h)(x) = h(g(f(x)))
    """
    def composed(value):
        result = value
        for fn in functions:
            result = fn(result)
        return result
    if functions:
        functools.update_wrapper(composed, functions[0])
    return composed


def identity(x):
    """Identity function — returns input unchanged."""
    return x


def constant(value):
    """Return a function that always returns the given value."""
    return lambda *args, **kwargs: value

def {{nama_decorator}}(func=None, arity=None):
    """Currying decorator. Transforms multi-arg function into curried form.
    @curry
    def add(a, b, c): return a + b + c
    add(1)(2)(3) == 6
    add(1, 2)(3) == 6
    add(1)(2, 3) == 6
    """
    def decorator(fn):
        n = arity if arity is not None else len(inspect.signature(fn).parameters)

        @functools.wraps(fn)
        def curried(*args, **kwargs):
            if len(args) + len(kwargs) >= n:
                return fn(*args, **kwargs)
            def next_curried(*more_args, **more_kwargs):
                return curried(*(args + more_args), **dict(kwargs, **more_kwargs))
            return next_curried

        curried._arity = n
        return curried

    if func is not None:
        return decorator(func)
    return decorator

def {{nama_fungsi}}(func, *right_args, **right_kwargs):
    """Partial application from the right.
    partial_right(fn, 3, 4)(1, 2) == fn(1, 2, 3, 4)
    Unlike functools.partial which binds from the left.
    """
    @functools.wraps(func)
    def wrapper(*left_args, **left_kwargs):
        merged_kwargs = dict(left_kwargs)
        merged_kwargs.update(right_kwargs)
        return func(*(left_args + right_args), **merged_kwargs)
    return wrapper


def flip(func):
    """Flip the first two arguments of a function.
    flip(f)(a, b) == f(b, a)
    """
    @functools.wraps(func)
    def wrapper(a, b, *args, **kwargs):
        return func(b, a, *args, **kwargs)
    return wrapper


def unary(func):
    """Wrap function to accept only one argument.
    unary(fn)(x, y, z) == fn(x)
    """
    @functools.wraps(func)
    def wrapper(arg):
        return func(arg)
    return wrapper


def n_ary(func, n):
    """Wrap function to accept exactly n arguments.
    n_ary(fn, 2)(a, b, c) == fn(a, b)
    """
    @functools.wraps(func)
    def wrapper(*args):
        return func(*args[:n])
    return wrapper

class {{nama_class}}:
    """Maybe monad. Wraps a value that might be None.
    Chains operations safely — if value is None, all subsequent ops return Nothing.
    """
    def __init__(self, value=None):
        self._value = value

    @property
    def value(self):
        return self._value

    @property
    def is_some(self):
        return self._value is not None

    @property
    def is_none(self):
        return self._value is None

    def get(self, key, default=None):
        """Dict key access, safe against None."""
        if self._value is None:
            return {{nama_class}}(None)
        try:
            if isinstance(self._value, dict):
                return {{nama_class}}(self._value.get(key, default))
            return {{nama_class}}(getattr(self._value, key, default))
        except (TypeError, AttributeError):
            return {{nama_class}}(None)

    def map(self, func):
        """Apply function to wrapped value if not None."""
        if self._value is None:
            return {{nama_class}}(None)
        try:
            return {{nama_class}}(func(self._value))
        except Exception:
            return {{nama_class}}(None)

    def flat_map(self, func):
        """Like map but func should return a Maybe."""
        if self._value is None:
            return {{nama_class}}(None)
        result = func(self._value)
        if isinstance(result, {{nama_class}}):
            return result
        return {{nama_class}}(result)

    def or_else(self, default):
        """Return value or default if None."""
        return self._value if self._value is not None else default

    def __repr__(self):
        return 'Maybe(%r)' % (self._value,)

    def __eq__(self, other):
        if isinstance(other, {{nama_class}}):
            return self._value == other._value
        return self._value == other


def {{nama_fungsi_just}}(value):
    """Create a Maybe with a value."""
    return {{nama_class}}(value)


def {{nama_fungsi_nothing}}():
    """Create an empty Maybe (None)."""
    return {{nama_class}}(None)

class {{nama_class}}:
    """Either monad: Right (success) or Left (error).
    Right('ok').map(str.upper) → Right('OK')
    Left('err').map(str.upper) → Left('err')
    """
    def __init__(self, value=None, error=None):
        self._value = value
        self._error = error

    @classmethod
    def right(cls, value):
        """Create a Right (success) instance."""
        return cls(value=value)

    @classmethod
    def left(cls, error):
        """Create a Left (error) instance."""
        return cls(error=error)

    @property
    def is_right(self):
        return self._error is None

    @property
    def is_left(self):
        return self._error is not None

    @property
    def value(self):
        return self._value

    @property
    def error(self):
        return self._error

    def map(self, func):
        """Apply function to value if Right."""
        if self.is_right:
            try:
                return {{nama_class}}.right(func(self._value))
            except Exception as e:
                return {{nama_class}}.left(str(e))
        return self

    def flat_map(self, func):
        """Like map, but func should return Either."""
        if self.is_right:
            try:
                return func(self._value)
            except Exception as e:
                return {{nama_class}}.left(str(e))
        return self

    def map_error(self, func):
        """Apply function to error if Left."""
        if self.is_left:
            return {{nama_class}}.left(func(self._error))
        return self

    def get_or_else(self, default):
        """Return value if Right, else default."""
        return self._value if self.is_right else default

    def __repr__(self):
        if self.is_right:
            return 'Right(%r)' % (self._value,)
        return 'Left(%r)' % (self._error,)

    def __eq__(self, other):
        if isinstance(other, {{nama_class}}):
            return self._value == other._value and self._error == other._error
        return False
